use std::collections::HashMap;

struct TrieNode {
    children: HashMap<char, Box<TrieNode>>,
    word: Option<String>,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode { children: HashMap::new(), word: None }
    }
}

fn find_words(board: Vec<Vec<char>>, words: Vec<String>) -> Vec<String> {
    let mut root = TrieNode::new();
    for word in &words {
        let mut node = &mut root;
        for ch in word.chars() {
            node = node.children.entry(ch).or_insert_with(|| Box::new(TrieNode::new()));
        }
        node.word = Some(word.clone());
    }

    let mut board = board;
    let rows = board.len() as i32;
    let cols = board[0].len() as i32;
    let mut result = Vec::new();

    fn dfs(board: &mut Vec<Vec<char>>, r: i32, c: i32, node: &mut TrieNode, result: &mut Vec<String>) {
        let ch = board[r as usize][c as usize];
        if ch == '#' { return; }
        if let Some(child) = node.children.get_mut(&ch) {
            if let Some(word) = child.word.take() {
                result.push(word);
            }
            board[r as usize][c as usize] = '#';
            for &(dr, dc) in &[(-1,0),(1,0),(0,-1),(0,1)] {
                let nr = r + dr;
                let nc = c + dc;
                if nr >= 0 && nr < rows && nc >= 0 && nc < cols {
                    dfs(board, nr, nc, child, result);
                }
            }
            board[r as usize][c as usize] = ch;
            if child.children.is_empty() {
                node.children.remove(&ch);
            }
        }
    }

    for r in 0..rows {
        for c in 0..cols {
            dfs(&mut board, r, c, &mut root, &mut result);
        }
    }
    result
}

