use std::collections::HashMap;

struct TrieNode {
    children: HashMap<char, Box<TrieNode>>,
    is_end: bool,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode { children: HashMap::new(), is_end: false }
    }
}

fn replace_words(dictionary: Vec<String>, sentence: String) -> String {
    let mut root = TrieNode::new();
    for word in &dictionary {
        let mut node = &mut root;
        for ch in word.chars() {
            node = node.children.entry(ch).or_insert_with(|| Box::new(TrieNode::new()));
        }
        node.is_end = true;
    }

    let words: Vec<String> = sentence.split_whitespace().map(String::from).collect();
    let mut result = Vec::new();
    for word in &words {
        let mut node = &root;
        let mut found = word.clone();
        for (i, ch) in word.chars().enumerate() {
            match node.children.get(&ch) {
                Some(child) => {
                    node = child;
                    if node.is_end {
                        found = word[..i+1].to_string();
                        break;
                    }
                }
                None => break,
            }
        }
        result.push(found);
    }
    result.join(" ")
}

