    isEnd    bool
}

type StreamChecker struct {
    root   *TrieNode
    buffer []byte
    maxLen int
}

func Constructor(words []string) StreamChecker {
    root := &TrieNode{}
    maxLen := 0
    for _, word := range words {
        node := root
        for i := len(word) - 1; i >= 0; i-- {
            idx := word[i] - 'a'
            if node.children[idx] == nil {
                node.children[idx] = &TrieNode{}
            }
            node = node.children[idx]
        }
        node.isEnd = true
        if len(word) > maxLen {
            maxLen = len(word)
        }
    }
    return StreamChecker{root: root, buffer: make([]byte, 0), maxLen: maxLen}
}

func (sc *StreamChecker) Query(letter byte) bool {
    sc.buffer = append(sc.buffer, letter)
    if len(sc.buffer) > sc.maxLen {
        sc.buffer = sc.buffer[1:]
    }
    node := sc.root
    for i := len(sc.buffer) - 1; i >= 0; i-- {
        idx := sc.buffer[i] - 'a'
        if node.children[idx] == nil {
            return false
        }
        node = node.children[idx]
        if node.isEnd {
            return true
        }
    }
    return false
}

