use std::collections::HashMap;

struct TrieNode {
    children: HashMap<char, Box<TrieNode>>,
    is_end: bool,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode { children: HashMap::new(), is_end: false }
    }
}

fn longest_word(words: Vec<String>) -> String {
    let mut root = TrieNode::new();
    for word in &words {
        let mut node = &mut root;
        for ch in word.chars() {
            node = node.children.entry(ch).or_insert_with(|| Box::new(TrieNode::new()));
        }
        node.is_end = true;
    }

    let mut result = String::new();
    fn dfs(node: &TrieNode, path: &mut String, result: &mut String) {
        let mut sorted_children: Vec<_> = node.children.iter().collect();
        sorted_children.sort_by_key(|(ch, _)| *ch);
        for (ch, child) in sorted_children {
            if child.is_end {
                path.push(*ch);
                if path.len() > result.len() {
                    *result = path.clone();
                }
                dfs(child, path, result);
                path.pop();
            }
        }
    }
    dfs(&root, &mut String::new(), &mut result);
    result
}

