class TrieNode {
    TrieNode[] children = new TrieNode[26];
    int wordIndex = -1;
    List<Integer> palindromeBelow = new ArrayList<>();
}

class Solution {
    public List<List<Integer>> palindromePairs(String[] words) {
        TrieNode root = new TrieNode();
        for (int i = 0; i < words.length; i++) {
            String rev = new StringBuilder(words[i]).reverse().toString();
            TrieNode node = root;
            for (int j = 0; j < rev.length(); j++) {
                if (isPalindrome(rev, j, rev.length() - 1)) {
                    node.palindromeBelow.add(i);
                }
                int idx = rev.charAt(j) - 'a';
                if (node.children[idx] == null) node.children[idx] = new TrieNode();
                node = node.children[idx];
            }
            node.wordIndex = i;
        }

        List<List<Integer>> result = new ArrayList<>();
        for (int i = 0; i < words.length; i++) {
            String word = words[i];
            TrieNode node = root;
            for (int j = 0; j < word.length(); j++) {
                if (node.wordIndex != -1 && node.wordIndex != i && isPalindrome(word, j, word.length() - 1)) {
                    result.add(Arrays.asList(i, node.wordIndex));
                }
                int idx = word.charAt(j) - 'a';
                if (node.children[idx] == null) break;
                node = node.children[idx];
                if (j == word.length() - 1) {
                    for (int k : node.palindromeBelow) {
                        if (i != k) result.add(Arrays.asList(i, k));
                    }
                }
            }
        }
        return result;
    }

    private boolean isPalindrome(String s, int left, int right) {
        while (left < right) {
            if (s.charAt(left++) != s.charAt(right--)) return false;
        }
        return true;
    }
}

