        if s[l] != s[r] {
            return false
        }
        l++
        r--
    }
    return true
}

func palindromePairs(words []string) [][]int {
    root := &TrieNode{wordIndex: -1}
    for i, word := range words {
        node := root
        revBytes := []byte(word)
        for i, j := 0, len(revBytes)-1; i < j; i, j = i+1, j-1 {
            revBytes[i], revBytes[j] = revBytes[j], revBytes[i]
        }
        rev := string(revBytes)
        for j := 0; j < len(rev); j++ {
            if isPalindrome(rev, j, len(rev)-1) {
                node.palindromeBelow = append(node.palindromeBelow, i)
            }
            idx := rev[j] - 'a'
            if node.children[idx] == nil {
                node.children[idx] = &TrieNode{wordIndex: -1}
            }
            node = node.children[idx]
        }
        node.wordIndex = i
    }

