use std::collections::HashMap;

struct TrieNode {
    children: HashMap<char, Box<TrieNode>>,
    word_index: i32,
    palindrome_below: Vec<usize>,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode { children: HashMap::new(), word_index: -1, palindrome_below: Vec::new() }
    }
}

fn is_palindrome(s: &str, mut left: usize, mut right: usize) -> bool {
    let bytes = s.as_bytes();
    while left < right {
        if bytes[left] != bytes[right] {
            return false;
        }
        left += 1;
        right -= 1;
    }
    true
}

fn palindrome_pairs(words: Vec<String>) -> Vec<Vec<i32>> {
    let mut root = TrieNode::new();
    for (i, word) in words.iter().enumerate() {
        let mut node = &mut root;
        let rev: String = word.chars().rev().collect();
        for (j, ch) in rev.chars().enumerate() {
            if is_palindrome(&rev, j, rev.len() - 1) {
                node.palindrome_below.push(i);
            }
            node = node.children.entry(ch).or_insert_with(|| Box::new(TrieNode::new()));
        }
        node.word_index = i as i32;
    }

    let mut result = Vec::new();
    for (i, word) in words.iter().enumerate() {
        let mut node = &root;
        for (j, ch) in word.chars().enumerate() {
            if node.word_index >= 0 && node.word_index as usize != i && is_palindrome(word, j, word.len() - 1) {
                result.push(vec![i as i32, node.word_index]);
            }
            match node.children.get(&ch) {
                Some(child) => node = child,
                None => break,
            }
            if j == word.len() - 1 {
                for &k in &node.palindrome_below {
                    if i != k {
                        result.push(vec![i as i32, k as i32]);
                    }
                }
            }
        }
    }
    result
}
